{"code": "import json
import re
from datetime import datetime

# Get the file path from the correctly named variable
file_path = var_functions.query_db_36

# Load the data
with open(file_path, 'r') as f:
    de_patents = json.load(f)

print(f"Loaded {len(de_patents)} German patents from 2019")

# Process the data
def parse_date(date_str):
    """Parse various date formats"""
    try:
        # Clean the string
        date_str = date_str.replace('dated', '').replace('the', '').replace('th,', '').replace('st,', '').replace('nd,', '').replace('rd,', '')
        date_str = date_str.replace('th', '').replace('st', '').replace('nd', '').replace('rd', '')
        date_str = date_str.strip()

        # Try different formats
        formats = ['%d %b %Y', '%b %d %Y', '%d %B %Y', '%B %d %Y']
        for fmt in formats:
            try:
                return datetime.strptime(date_str, fmt)
            except:
                continue
        return None
    except:
        return None

def get_cpc_level4(code):
    """Extract CPC level 4 code (first 4 chars)"""
    if code and len(code) >= 4:
        return code[:4]
    return None

# Count patents by month and CPC
cpc_by_month = {}
total_by_month = {}

for patent in de_patents:
    # Parse grant date
    grant_date = parse_date(patent['grant_date'])
    if not grant_date or grant_date.year != 2019:
        continue

    month = grant_date.month

    # Only second half of 2019 (months 7-12)
    if month < 7:
        continue

    # Initialize month counters
    if month not in cpc_by_month:
        cpc_by_month[month] = {}
    if month not in total_by_month:
        total_by_month[month] = 0

    total_by_month[month] += 1

    # Parse CPC codes
    try:
        cpc_data = patent['cpc']
        if cpc_data:
            cpc_codes = json.loads(cpc_data)
            level4_codes = set()

            for cpc in cpc_codes:
                if 'code' in cpc:
                    level4 = get_cpc_level4(cpc['code'])
                    if level4:
                        level4_codes.add(level4)

            # Count each unique CPC code for this patent
            for code in level4_codes:
                cpc_by_month[month][code] = cpc_by_month[month].get(code, 0) + 1
    except:
        continue

print(f"Second half 2019 months: {list(cpc_by_month.keys())}")
print(f"Total patents in second half: {sum(total_by_month.values())}")

result_summary = {
    'total_patents_second_half': sum(total_by_month.values()),
    'patents_by_month': total_by_month,
    'cpc_codes_by_month': {month: dict(counts) for month, counts in cpc_by_month.items()}
}

print(result_summary)

print("__RESULT__:")
print(json.dumps(result_summary))"}

{"code": "import json
import re
from datetime import datetime

# Access file path - the variable name should be available in locals
file_var = None
for key in locals():
    if 'query_db' in key and '36' in key:
        file_var = key
        break

if file_var:
    file_path = locals()[file_var]
    with open(file_path, 'r') as f:
        de_patents = json.load(f)

    print(f"Loaded {len(de_patents)} patents")

    # Parse dates and filter for second half 2019
    valid_patents = []
    for p in de_patents:
        date_str = p['grant_date']
        # Simple month extraction for second half
        if 'Jul' in date_str or 'Aug' in date_str or 'Sep' in date_str or 'Oct' in date_str or 'Nov' in date_str or 'Dec' in date_str:
            if '2019' in date_str:
                valid_patents.append(p)

    print(f"Second half 2019 patents: {len(valid_patents)}")

    # Count CPC codes at level 4
    from collections import Counter
    cpc_counts = Counter()

    for patent in valid_patents:
        try:
            cpc_data = json.loads(patent['cpc'])
            codes = set()
            for item in cpc_data:
                if 'code' in item:
                    code = item['code'][:4]  # Level 4
                    codes.add(code)
            for code in codes:
                cpc_counts[code] += 1
        except:
            pass

    print(f"Top 10 CPC level 4 codes: {cpc_counts.most_common(10)}")

    result = {
        'total_second_half': len(valid_patents),
        'top_cpc': cpc_counts.most_common(10)
    }

    print("__RESULT__:")
    print(json.dumps(result))
else:
    print("File variable not found")
    print("Available keys:", [k for k in locals().keys() if 'query' in k])"}

