{"code": "import json
import re
from collections import defaultdict, Counter

# Get the file path from storage variables
all_vars = list(locals().keys())
query_vars = [v for v in all_vars if 'query_db' in v and '72' in v]

if not query_vars:
    print("No query_db variable found with 72")
    # Try to find the most recent query_db variable
    query_vars = [v for v in all_vars if 'query_db' in v]
    print(f"Available query_db variables: {query_vars}")

if query_vars:
    var_name = query_vars[0]
    file_path = locals()[var_name]
    print(f"Using variable {var_name}: {file_path}")

    # Load patent data
    try:
        with open(file_path, 'r') as f:
            patents = json.load(f)
        print(f"Successfully loaded {len(patents)} patents")
    except Exception as e:
        print(f"Error loading file: {e}")
        patents = []
else:
    print("No query_db variables found at all")
    patents = []

# Function to extract month from grant date
def extract_month(date_str):
    """Extract month from grant date string"""
    if not date_str:
        return None
    date_str_lower = date_str.lower()
    months = {
        'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
        'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
    }
    for month_abbr, month_num in months.items():
        if month_abbr in date_str_lower:
            return month_num
    return None

# Function to extract CPC level 4 codes
def extract_cpc_level4(cpc_json):
    """Extract CPC codes at level 4 (first 4 characters)"""
    if not cpc_json or cpc_json == '[]':
        return []
    try:
        cpc_list = json.loads(cpc_json)
        level4_codes = set()
        for item in cpc_list:
            if isinstance(item, dict) and 'code' in item:
                code = item['code']
                if len(code) >= 4:
                    level4_codes.add(code[:4])
        return list(level4_codes)
    except:
        return []

# Process patents: count filings per CPC level 4 per month for second half 2019
cpc_monthly_counts = defaultdict(lambda: defaultdict(int))  # {cpc: {month: count}}
second_half_patents = []

for patent in patents:
    grant_date = patent.get('grant_date', '')
    if not grant_date or '2019' not in grant_date:
        continue

    month = extract_month(grant_date)
    if not month or month < 7:  # Filter for second half (July-December)
        continue

    cpc_codes = extract_cpc_level4(patent.get('cpc', ''))
    if not cpc_codes:
        continue

    second_half_patents.append(patent)
    for cpc in cpc_codes:
        cpc_monthly_counts[cpc][month] += 1

print(f"\nPatents in second half 2019: {len(second_half_patents)}")
print(f"Unique CPC level 4 codes: {len(cpc_monthly_counts)}")

# Calculate Exponential Moving Average (EMA) for each CPC code
alpha = 0.1  # Smoothing factor

cpc_ema_results = {}
best_cpc_periods = {}

for cpc in cpc_monthly_counts:
    ema = 0
    best_ema = 0
    best_month = None
    best_count = 0

    # Process months in chronological order (July to December)
    for month in range(7, 13):
        count = cpc_monthly_counts[cpc][month]

        # EMA formula: EMA_t = α * value_t + (1-α) * EMA_{t-1}
        if month == 7:  # First period
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        # Track best (highest EMA) period
        if ema > best_ema:
            best_ema = ema
            best_month = month
            best_count = count

    cpc_ema_results[cpc] = {
        'best_ema': best_ema,
        'best_month': best_month,
        'patents_in_month': best_count
    }

print(f"\nTop 20 CPC codes by EMA in second half 2019:")
sorted_cpc = sorted(cpc_ema_results.items(), key=lambda x: x[1]['best_ema'], reverse=True)
for i, (cpc, data) in enumerate(sorted_cpc[:20]):
    print(f"{i+1:2d}. CPC {cpc}: Best EMA = {data['best_ema']:.2f} (in month {data['best_month']}, {data['patents_in_month']} patents)")

# Save results for next step
result_data = {
    'top_cpc_codes': sorted_cpc[:15],
    'cpc_ema_results': cpc_ema_results,
    'second_half_patents': len(second_half_patents)
}

print("\n__RESULT__:")
print(json.dumps({
    'total_patents': len(second_half_patents),
    'total_cpc_codes': len(cpc_monthly_counts),
    'top_cpc_count': len(sorted_cpc[:15])
}))"}

