{"code": "import json
import re
from collections import defaultdict

# Get file path from storage
file_path = var_functions.query_db_88
print('Loading patent data...')

# Load the patent data
with open(file_path, 'r') as f:
    patents = json.load(f)

print('Patents loaded:', len(patents))

# Helper functions
months_dict = {'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6, 'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12}

def extract_month(date_str):
    if not date_str:
        return None
    date_lower = date_str.lower()
    for abbr, num in months_dict.items():
        if abbr in date_lower:
            return num
    return None

def extract_cpc_level4(cpc_json):
    if not cpc_json or cpc_json == '[]':
        return []
    try:
        cpc_list = json.loads(cpc_json)
        codes = set()
        for item in cpc_list:
            if isinstance(item, dict) and 'code' in item:
                code = item['code']
                if len(code) >= 4:
                    codes.add(code[:4])
        return list(codes)
    except:
        return []

# Count patents by CPC and month (second half 2019 only)
cpc_month_counts = defaultdict(lambda: defaultdict(int))
second_half_count = 0

for patent in patents:
    grant_date = patent.get('grant_date', '')
    month = extract_month(grant_date)

    if not month or month < 7:
        continue

    cpc_codes = extract_cpc_level4(patent.get('cpc', ''))
    if not cpc_codes:
        continue

    second_half_count += 1
    for cpc in cpc_codes:
        cpc_month_counts[cpc][month] += 1

print('Second half 2019 patents:', second_half_count)
print('Unique CPC codes:', len(cpc_month_counts))

# Calculate EMA (alpha = 0.1)
alpha = 0.1
best_ema_results = {}

for cpc in cpc_month_counts:
    ema = 0
    best_ema = 0
    best_month = None

    for month in range(7, 13):
        count = cpc_month_counts[cpc][month]
        if month == 7:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = month

    best_ema_results[cpc] = {'ema': best_ema, 'month': best_month}

# Sort by EMA
sorted_results = sorted(best_ema_results.items(), key=lambda x: x[1]['ema'], reverse=True)

print('Top 15 CPC by EMA:')
for i, (cpc, data) in enumerate(sorted_results[:15]):
    print(str(i+1) + '. CPC ' + cpc + ': EMA=' + str(round(data['ema'], 2)) + ', Month=' + str(data['month']))

output = []
for cpc, data in sorted_results[:15]:
    output.append({
        'cpc_code': cpc,
        'best_ema': data['ema'],
        'best_month': data['month']
    })

print('__RESULT__:')
print(json.dumps(output))"}

